final class Money
{
    public function __construct(
        private readonly int $amount,    // in cents
        private readonly string $currency,
    ) {}

    public function add(Money $other): self
    {
        if ($this->currency !== $other->currency) {
            throw new \DomainException('Currency mismatch');
        }
        return new self($this->amount + $other->amount, $this->currency);
    }
}

interface OrderRepository
{
    public function findById(OrderId $id): ?Order;
    public function findPendingOlderThan(\DateTimeImmutable $cutoff): array;
    public function save(Order $order): void;
    public function remove(Order $order): void;
}

final class Order
{
    private function __construct(
        private readonly OrderId $id,
        private readonly CustomerId $customerId,
        private array $items = [],
    ) {}

    public static function place(CustomerId $customerId, array $items): self
    {
        if (empty($items)) {
            throw new \DomainException('An order must have at least one item.');
        }
        return new self(OrderId::generate(), $customerId, $items);
    }
}

interface ShippingStrategy
{
    public function calculate(Order $order): Money;
}

class StandardShipping implements ShippingStrategy { /* ... */ }
class ExpressShipping implements ShippingStrategy { /* ... */ }

class OrderPricer
{
    public function __construct(private readonly ShippingStrategy $shipping) {}

    public function total(Order $order): Money
    {
        return $order->subtotal()->add($this->shipping->calculate($order));
    }
}

class OrderService
{
    public function __construct(
        private readonly OrderRepository $orders,
        private readonly EventBus $events,
        private readonly Clock $clock,
    ) {}
}

// In a test — plain PHP, no container:
$service = new OrderService(
    new InMemoryOrderRepository(),
    new RecordingEventBus(),
    new FixedClock('2026-03-06'),
